import { tags } from 'decantr/tags';
import { createSignal, onMount, onDestroy } from 'decantr/state';
import { css } from 'decantr/css';
import { icon } from 'decantr/components';

code.example:
function HelpModal({ shortcuts, onClose }) {
  const { div, input, span, kbd, h3 } = tags;
  const [search, setSearch] = createSignal('');

  const handleKeyDown = (e) => {
    if (e.key === 'Escape' || e.key === '?') {
      e.preventDefault();
      onClose();
    }
  };

  onMount(() => document.addEventListener('keydown', handleKeyDown));
  onDestroy(() => document.removeEventListener('keydown', handleKeyDown));

  const filteredShortcuts = () => {
    const q = search().toLowerCase();
    if (!q) return shortcuts;
    return shortcuts.map(cat => ({
      ...cat,
      items: cat.items.filter(s =>
        s.key.toLowerCase().includes(q) || s.description.toLowerCase().includes(q)
      )
    })).filter(cat => cat.items.length > 0);
  };

  return div({ class: css('_fixed _inset0 _flex _center _z[100] _bg[rgba(0,0,0,0.9)]'), onclick: onClose },
    div({ class: css('term-panel _w[600px] _mw[90vw] _maxh[80vh] _flex _col'), onclick: (e) => e.stopPropagation() },
      div({ class: css('_flex _aic _jcsb _p3 _borderB _bordercolor[#333]') },
        span({ class: css('_fontbold _text[1.2em]') }, 'Keyboard Shortcuts'),
        span({ class: css('_fgmuted _cursor[pointer]'), onclick: onClose }, '(?) to close')
      ),
      div({ class: css('_p3 _borderB _bordercolor[#333]') },
        input({
          type: 'text',
          placeholder: 'Search shortcuts...',
          value: search,
          oninput: (e) => setSearch(e.target.value),
          class: css('_wfull _bg[transparent] _border _bordercolor[#333] _p2 _fggreen _mono'),
          autofocus: true
        })
      ),
      div({ class: css('_flex1 _overflow[auto] _p3') },
        ...filteredShortcuts().map(category =>
          div({ class: css('_mb4') },
            h3({ class: css('_fgmuted _textsm _uppercase _mb2 _tracking[wider]') }, category.name),
            ...category.items.map(shortcut =>
              div({ class: css('_flex _aic _jcsb _py1') },
                span({}, shortcut.description),
                div({ class: css('_flex _aic _gap1') },
                  ...shortcut.key.split('+').map(k =>
                    kbd({ class: css('term-hotkey _px2 _py1 _border _bordercolor[#555] _r1 _textsm') }, k)
                  )
                )
              )
            )
          )
        )
      ),
      div({ class: css('_p3 _borderT _bordercolor[#333] _textsm _fgmuted _textcenter') },
        'Press ', kbd({ class: css('_px1 _border _bordercolor[#555]') }, '?'), ' to toggle this help'
      )
    )
  );
}

function MinimalHelp({ shortcuts, onClose }) {
  const { div, span, kbd } = tags;

  return div({ class: css('_fixed _inset0 _flex _center _z[100] _bg[rgba(0,0,0,0.8)]'), onclick: onClose },
    div({ class: css('term-panel _p4 _w[400px]'), onclick: (e) => e.stopPropagation() },
      div({ class: css('_fontbold _mb3 _textcenter') }, 'Quick Reference'),
      div({ class: css('_grid _gap2'), style: 'grid-template-columns: auto 1fr' },
        ...shortcuts.flatMap(s => [
          kbd({ class: css('term-hotkey _px2 _border _bordercolor[#555] _textsm') }, s.key),
          span({ class: css('_fgmuted') }, s.description)
        ])
      ),
      div({ class: css('_mt3 _textcenter _textsm _fgmuted') }, 'Press any key to close')
    )
  );
}

